    const N = s.length;

    // 1. Count total number of '1's
    let T1 = 0;
    for (let i = 0; i < N; i++) {
        if (s[i] === '1') {
            T1++;
        }
    }

    // Case 1: Target S' = 0^N
    // Cost is the number of '1's we must flip to '0'.
    const C0 = T1;

    // Case 2: Target S' = 1^N
    // Cost is the number of '0's we must flip to '1'.
    const C1 = N - T1;

    // Case 3: Target S' = 0^a 1 0^b (Single '1' allowed)
    let C_min_3 = Infinity;

    for (let j = 0; j < N; j++) {
        let Cj;

        if (s[j] === '0') {
            // Target requires '1' at j. Cost: 1 (flip s[j]) + T1 (flip all existing 1s to 0)
            Cj = 1 + T1;
        } else { // s[j] === '1'
            // Target requires '1' at j. Cost: 0 (keep s[j]) + (T1 - 1) (flip all other 1s to 0)
            Cj = T1 - 1;
        }

        if (Cj < C_min_3) {
            C_min_3 = Cj;
        }
    }

    // The minimum cost is the minimum across all three valid target structures.
    return Math.min(C0, C1, C_min_3);
}

